package com.cognizant.springmockito;import static org.mockito.Mockito.*;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.boot.test.mock.mockito.MockBean;import org.springframework.test.web.servlet.MockMvc;@SpringBootTest @AutoConfigureMockMvc public class UserIntegrationTest {@Autowired MockMvc mockMvc;@MockBean UserService userService;@Test void testGetUser() throws Exception {when(userService.getUserById(1L)).thenReturn(new User(1L,"Aman"));mockMvc.perform(get("/users/1")).andExpect(status().isOk()).andExpect(jsonPath("$.id").value(1)).andExpect(jsonPath("$.name").value("Aman"));verify(userService).getUserById(1L);}}
